import { useMemo, useState } from 'react';
import { Link, useSearchParams } from 'react-router-dom';
import { confirmPasswordReset } from '@/api/auth';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';
import { InlineMessage } from '@/components/feedback/InlineMessage';

function strengthLabel(password: string) {
  if (password.length >= 12) return 'Sterk';
  if (password.length >= 8) return 'Redelijk';
  return 'Zwak';
}

export function ResetPasswordPage() {
  const [searchParams] = useSearchParams();
  const token = searchParams.get('token') || '';
  const [password, setPassword] = useState('');
  const [message, setMessage] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);
  const strength = useMemo(() => strengthLabel(password), [password]);

  async function handleSubmit(event: React.FormEvent) {
    event.preventDefault();
    setSubmitting(true);
    try {
      await confirmPasswordReset({ token, password });
      setMessage('Wachtwoord succesvol gewijzigd.');
    } catch (error) {
      setMessage(error instanceof Error ? error.message : 'Reset mislukt.');
    } finally {
      setSubmitting(false);
    }
  }

  return (
    <div className="auth-layout">
      <Card className="auth-card">
        <div>
          <div className="eyebrow">Nieuw wachtwoord</div>
          <h1>Stel een nieuw wachtwoord in</h1>
        </div>
        {message ? <InlineMessage tone={message.includes('succesvol') ? 'success' : 'danger'}>{message}</InlineMessage> : null}
        <form className="form-grid" onSubmit={handleSubmit}>
          <label>
            <span>Token</span>
            <Input value={token} disabled />
          </label>
          <label>
            <span>Nieuw wachtwoord</span>
            <Input type="password" value={password} onChange={(event) => setPassword(event.target.value)} required />
            <small className="list-subtle">Sterkte: {strength}</small>
          </label>
          <Button type="submit" disabled={submitting || !token}>{submitting ? 'Bezig...' : 'Wachtwoord opslaan'}</Button>
        </form>
        <Link to="/login">Terug naar inloggen</Link>
      </Card>
    </div>
  );
}
