import { useState } from 'react';
import { Link } from 'react-router-dom';
import { requestPasswordReset } from '@/api/auth';
import { Button } from '@/components/ui/Button';
import { Card } from '@/components/ui/Card';
import { Input } from '@/components/ui/Input';
import { InlineMessage } from '@/components/feedback/InlineMessage';

export function ForgotPasswordPage() {
  const [email, setEmail] = useState('');
  const [message, setMessage] = useState<string | null>(null);
  const [submitting, setSubmitting] = useState(false);

  async function handleSubmit(event: React.FormEvent) {
    event.preventDefault();
    setSubmitting(true);
    try {
      await requestPasswordReset(email);
    } finally {
      setMessage('Als dit account bestaat, is een resetlink verstuurd.');
      setSubmitting(false);
    }
  }

  return (
    <div className="auth-layout">
      <Card className="auth-card">
        <div>
          <div className="eyebrow">Wachtwoord vergeten</div>
          <h1>Vraag een resetlink aan</h1>
          <p>De frontend gebruikt het bestaande reset-password request-endpoint.</p>
        </div>
        {message ? <InlineMessage tone="success">{message}</InlineMessage> : null}
        <form className="form-grid" onSubmit={handleSubmit}>
          <label>
            <span>E-mail</span>
            <Input type="email" value={email} onChange={(event) => setEmail(event.target.value)} required />
          </label>
          <Button type="submit" disabled={submitting}>{submitting ? 'Bezig...' : 'Resetlink aanvragen'}</Button>
        </form>
        <Link to="/login">Terug naar inloggen</Link>
      </Card>
    </div>
  );
}
